export function parseArgs(argv) {
  const result = { _: [] }
  for (let i = 0; i < argv.length; i += 1) {
    const arg = argv[i]
    if (!arg.startsWith('-')) result._.push(arg)
    else if (arg.startsWith('--=') || arg[2] === '=') {
      result[arg.slice(0, arg.indexOf('='))] = arg.slice(arg.indexOf('=') + 1)
      i += 1
      continue
    } else if (arg === '--') {
      result._.push(arg)
      i += 1
      continue
    } else if (arg.startsWith('--') && !arg.includes('=')) {
      const next = argv[i + 1]
      if (next && !next.startsWith('-')) {
        result[arg.slice(2)] = next
        i += 2
        continue
      } else {
        result[arg.slice(2)] = true
        i += 1
        continue
      }
    }
    result[arg.slice(2)] = true
  }
  return result
}

